import{j as e}from"./index-BPk5_WeR.js";function n(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:4",children:"Every Amazon DSP owner has the same Monday morning ritual: open Cortex, look at the weekly scorecard, and try to work out which driver, which route, or which day dragged the numbers. If your status moved from Fantastic Plus to Fantastic — or worse, from Fantastic to Great — you've got a week to figure out what broke and prove you can fix it."}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:10",children:"The good news: scorecards almost always slip for predictable, fixable reasons. Below is the per-metric playbook we see working with UK Amazon DSPs."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:15",children:"What the Amazon Cortex scorecard actually measures"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:16",children:"The Cortex DA scorecard rolls six core metrics into a weekly status banner (Fantastic Plus, Fantastic, Great, Fair, Poor). Each metric is a leading indicator of how well your fleet executed against Amazon's promise to the customer. Understanding them in plain English is the first step:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:21",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:22",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:23",children:"DCR (Delivery Completion Rate)"})," — the share of assigned stops that were actually completed. Misses come from undelivered packages, returns to station, and incomplete waves."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:26",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:27",children:"DPMO (Defects Per Million Opportunities)"})," — physical defects: damages, missing items, wrong addresses, lost packages. Counted per million stops, so even small absolute numbers move the metric."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:31",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:32",children:"DNR (Delivered Not Received)"})," — customer-reported claims that a package was marked delivered but never arrived. Often tied to specific drivers or specific addresses."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:35",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:36",children:"POD (Photo on Delivery)"})," — compliance with the photo-on-delivery requirement for drop-offs. Low POD scores almost always cluster around a small number of drivers."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:39",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:40",children:"CC (Contact Compliance)"})," — drivers using the Mentor app to contact customers when deliveries can't complete. Skipped contacts compound into DNR and DCR misses downstream."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:43",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:44",children:"CDF (Customer Delivery Feedback)"})," — direct customer feedback rolled up into a score. Soft signal but it correlates tightly with CC and POD."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:49",children:"Why scorecards drift, even when nothing has obviously gone wrong"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:50",children:`Most DSPs we talk to don't have a "bad fleet" problem. They have a visibility problem. You see the weekly scorecard on Monday — but the events that produced it happened across hundreds of stops, on ten different routes, over seven days. By the time you're trying to fix it, the people involved have forgotten the specifics.`}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:56",children:"The structural fix is to look at metrics live, per driver, mid-week — not as a summary after the fact. The tactical fixes below assume you can."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:61",children:"DCR — lift it with route-handoff discipline"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:62",children:"DCR drops happen on the routes that finish late, run out of time, or get returned partially complete. Two interventions:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:66",children:[e.jsx("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:67",children:"Track planned vs actual finish times per route. Routes that consistently finish in the red are either over-stopped or assigned to drivers who need a route swap."}),e.jsx("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:71",children:'Cut "return to station with packages" events. When a driver is on track to RTS with parcels, get them on the phone before the end of the wave — almost always you can either reroute the remaining stops or get them a one-hour extension.'})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:78",children:"DPMO — fix the upstream van check, not the downstream defect"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:79",children:"Most DPMO defects you can prevent — damaged parcels, wrong-address attempts, missing items — trace back to two events: a sloppy van load and an unchecked van. Both are upstream of dispatch."}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:83",children:"A daily van inspection with photos (yes, every day) catches the small issues that turn into customer complaints by Friday. And a pre-departure check on package counts catches the missing-item DPMO hits before the van leaves the station. The drivers who skip these checks are usually the drivers driving your DPMO."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:90",children:"DNR — investigate every claim, even when it feels unfair"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:91",children:"DNRs feel like the metric you can't control, but the patterns are obvious once you look. Claims tend to cluster around three things: specific drivers, specific addresses, and specific times of day (usually evening drops in low-light conditions). Pull the last 30 days of DNR claims, sort by driver, and the top two names will almost always be over-represented. That's where the conversation starts."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:98",children:"POD — make it visible to drivers daily, not weekly"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:99",children:"POD compliance is the easiest metric to fix because it's a behaviour, not a skill. The drivers with low POD scores almost always know exactly which photos they skipped — they just don't see the consequence until your Monday meeting. Surface every driver's personal POD score back to them daily, on their phone, and the metric moves within two weeks."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:106",children:"CC — train it as a habit, not a one-off briefing"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:107",children:"Contact Compliance is about drivers actually using the Mentor app's contact buttons when they can't complete a delivery. The fix is repetition: review CC misses in the morning huddle, the same way you review safety. After three weeks of consistent feedback, drivers internalise it."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:113",children:"CDF — the lagging indicator that confirms the rest is working"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:114",children:"Customer Delivery Feedback rises automatically when POD and CC rise. There's no separate lever for it. If the other five metrics are improving and CDF isn't, look at handover quality — are drivers leaving packages in places customers don't expect, or rushing the doorstep interaction."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:120",children:"The Monday-to-Friday review rhythm"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:121",children:"Owners who consistently hit Fantastic Plus run the same loop:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:124",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:125",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:126",children:"Monday:"})," review the previous week's scorecard with the OSM and identify the one or two metrics most at risk."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:129",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:130",children:"Tuesday–Thursday:"})," short morning huddles focused on yesterday's actual driver-level numbers, not the fleet average."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:133",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:134",children:"Friday:"})," a quick scan of the week's trajectory — escalations for any driver consistently below standard, recognition for the top performers."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:138",children:"The thing that breaks this loop, every time, is data. If your OSM is rebuilding metric tables in Excel every morning instead of running the huddle, the loop dies by Wednesday."}),e.jsx("h2",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:143",children:"Where DSPOps fits in"}),e.jsx("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:144",children:"DSPOps connects to Amazon Cortex and pulls every scorecard metric in live, per driver and per route. Your OSM opens the dashboard, sees the three drivers most likely to drag this week's score, and runs the huddle in two minutes. Drivers see their own metrics inside the driver portal — the ones who care about being top of the leaderboard self-correct without a meeting."}),e.jsxs("p",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:150",children:["If you want to see what your DSP's scorecard looks like inside DSPOps, you can"," ",e.jsx("a",{"data-loc":"client/src/content/blog/improve-amazon-cortex-scorecard.tsx:152",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"book a 20-minute demo"})," ","— we'll set up your data live during the call."]})]})}function r(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:4",children:"If you manage a UK Amazon DSP, your Amazon Cortex DCR score is the metric that can define your entire week. A single bad day — a wave that ran over time, a batch of returns, a driver who went off-route — shows up on Monday as a percentage drop that feels impossible to trace. This guide explains exactly what DCR measures, what separates a Fantastic score from a Fair one, the most common reasons it falls, and the specific steps you can take to push it back up before the next weekly scorecard lands."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:13",children:"What DCR actually measures — and why Amazon weights it so heavily"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:14",children:"DCR stands for Delivery Completion Rate. It measures the share of your assigned stops that were actually delivered successfully during the wave. If your driver was allocated 120 stops and completed 117, their DCR for that route is 97.5%."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:19",children:"Amazon weights DCR heavily because it is the most direct proxy for customer promise fulfilment. Every stop that does not complete either generates a redelivery attempt (which costs Amazon money), a customer complaint (which increases your DNR exposure), or a returned parcel (which the customer must then chase). Across a fleet of ten drivers doing six days a week, even a 1% DCR miss compounds quickly."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:26",children:"DCR is calculated weekly across your entire DA fleet. It does not average out neatly — a single driver completing three short waves with several missed stops can pull down a fleet that is otherwise performing well. That is why understanding DCR at the individual driver and route level matters far more than watching the fleet headline figure alone."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:33",children:"What a good Amazon Cortex DCR score looks like"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:34",children:"Amazon's Cortex scoring bands work roughly as follows (exact thresholds vary by programme and region, but UK brackets align broadly with these figures):"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:38",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:39",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:40",children:"Fantastic Plus:"})," DCR at or above 98.0%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:42",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:43",children:"Fantastic:"})," DCR between 96.5% and 97.9%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:45",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:46",children:"Great:"})," DCR between 95.0% and 96.4%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:48",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:49",children:"Fair:"})," DCR between 90.0% and 94.9%"]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:51",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:52",children:"Poor:"})," DCR below 90.0%"]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:55",children:"Most DSPs aiming for Fantastic Plus need every driver consistently above 97%. That sounds achievable until you factor in long days, Same-Day Delivery waves, bad weather, and the occasional driver who ends a shift early."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:60",children:"The target to aim for is not 96% — it is 98% and above, because that is the buffer that absorbs your worst-performing route on your worst day of the week and still keeps you in the top band. Anything below 95% starts to attract attention from your Station Operations Manager and can affect your zone and route allocation in subsequent weeks."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:67",children:"The five most common reasons DCR drops"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:68",children:"Understanding why DCR falls is the first step to fixing it. These are the five patterns seen most often across UK DSPs:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:72",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:73",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:74",children:"Waves that run over time."})," When a driver has 130 stops and a 10-hour shift, the maths do not work. Stops that cannot be completed before the wave closes automatically count against DCR. Over-loading happens when route planning does not account for realistic completion rates, traffic density, or stop complexity."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:79",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:80",children:"Returns to station with packages."})," If a driver ends the day with undelivered parcels rather than attempting every stop, those count directly against DCR. This is often a discipline issue, but it can also be a training one — drivers who do not understand the consequence of leaving stops undelivered will repeat the behaviour."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:85",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:86",children:"Failed attempts at problem addresses."})," Some addresses generate repeated failures — gated properties, businesses that close early, access codes that do not work. Each failed attempt on an address that was never going to be deliverable drags the score without the driver doing anything wrong."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:91",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:92",children:"Same-Day Delivery (SDD) wave compression."})," SDD waves have tighter time windows and less tolerance for exceptions. A driver handling both standard and SDD on the same day is more likely to leave stops incomplete because of the competing time pressure."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:96",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:97",children:"Inexperienced drivers on dense urban routes."})," New drivers in city centres take longer to locate addresses, struggle with access, and are more likely to miss difficult deliveries. Assigning newer drivers to routes with a high stop density and tight timing is a reliable way to pull DCR down."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:104",children:"A per-driver playbook to fix it this week"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:105",children:"DCR improvement happens at the driver level, not the fleet level. Here is the sequence that works:"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:109",children:"Pull the last four weeks of DCR data for every driver individually. Sort it lowest to highest. The bottom three or four drivers will almost always account for more than half of your DCR gap. That is where to focus first."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:114",children:"For each driver below 96%, work through these steps:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:117",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:118",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:119",children:"Identify the specific routes or waves where they missed."})," Was it the same route each time? If so, the route is likely over-stopped, not the driver."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:122",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:123",children:"Check whether incomplete stops fell at the start or end of the wave."})," ","Late-day misses suggest a time management issue. Early misses point to address-level problems."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:127",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:128",children:"Reroute or rebalance if the route itself is the problem."})," Some routes genuinely cannot be completed in the time window allocated. No amount of driver coaching fixes a structural mismatch."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:132",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:133",children:"Run a one-to-one conversation — not a group briefing."})," Drivers respond differently when they see their own score rather than the fleet average. A targeted conversation about their specific numbers lands differently from a Monday morning announcement about DCR being down."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:139",children:"Track progress daily through the week. By Thursday you will know whether the changes are working or whether a different intervention is needed before Monday's scorecard."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:144",children:"How to spot a falling DCR before the weekly scorecard lands"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:145",children:"The weekly scorecard is a lagging indicator. By Monday, the damage is already done. DSPs that consistently hit Fantastic Plus have real-time or daily visibility into the signals that predict DCR — not the score itself, but the events that produce it."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:150",children:"Indicators to watch mid-week:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:153",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:154",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:155",children:"Waves closing with packages still on the van."})," If your OSM can see at 4 pm that a driver has 15 stops remaining with 45 minutes of wave time left, intervention is still possible — a phone call, a route swap, a time extension request to the station."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:159",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:160",children:"Return-to-station (RTS) events."})," Every RTS event with packages still on board is a direct DCR miss. Each one should generate an alert the same day so it can be investigated and addressed before it happens again the next morning."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:164",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:165",children:"Incomplete-stop patterns clustering around specific drivers."})," One driver missing five stops across three days is a different problem from three drivers missing two stops each. The former needs an individual intervention; the latter probably needs a route or timing review."]})]}),e.jsxs("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:171",children:["Linking your Cortex data to a live"," ",e.jsx("a",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:173",href:"/driver-performance-tracking",children:"driver performance tracking"})," tool is what separates reactive Monday reviews from proactive Wednesday fixes. The DSPs that hold Fantastic Plus week after week are not lucky — they see the problem on Wednesday and resolve it before the wave closes."]}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:179",children:"Frequently asked questions"}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:181",children:"What is a good DCR score on Amazon Cortex?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:182",children:"A DCR of 98% or above puts you in the Fantastic Plus band, which is the target for DSPs who want maximum flexibility on route awards and zone allocation. Fantastic (96.5%–97.9%) is acceptable but leaves no buffer for a difficult week. Anything below 95% (Great band or lower) starts to attract scrutiny from your Station Operations Manager and can affect future route and zone assignments."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:190",children:"Why is my DCR low even when my drivers are completing their routes?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:191",children:"DCR misses do not always mean drivers are skipping stops deliberately. Common hidden causes include waves timed too tightly so late stops close before they can be completed, Same-Day Delivery schedule pressure bleeding into standard routes, and problem addresses that generate automatic fails regardless of how many attempts are made. Check your incomplete stops at the route level rather than the fleet level to find the pattern — it is nearly always concentrated on a small number of routes or drivers."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:200",children:"How often does DCR update in Amazon Cortex?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:201",children:"Amazon Cortex updates its DA scorecard metrics weekly. The scorecard visible on Monday reflects activity from the previous week (typically Monday to Sunday). There is no live DCR figure within Cortex itself, which is why DSPs who need intra-week visibility have to pull metrics via a connected tool rather than waiting for the weekly reset. By the time you see a low score in Cortex, you are already a week behind."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:209",children:"Does one driver's low DCR affect my whole fleet score?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:210",children:"Yes. DCR is calculated across your entire DA fleet. A single driver completing three partial waves in a week can pull your fleet DCR down by 0.5–1.0 percentage points depending on fleet size. This is why per-driver visibility matters more than the headline fleet average — the fleet number hides the individual contributors."}),e.jsx("h3",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:217",children:"Can I dispute a DCR miss if the stop was undeliverable?"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:218",children:"In some cases, yes. Amazon allows exception requests for certain stop types — gated properties, incorrect addresses supplied by the customer, and customer cancellations. The process varies by station, but your Station Operations Manager is the first contact. Document the specific stop details and the reason for non-completion at the time it happens, not after the scorecard has landed — retrospective disputes are harder to support without same-day evidence."}),e.jsxs("p",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:227",children:["If you want daily DCR visibility without rebuilding your tracking in spreadsheets, DSPOps connects to Amazon Cortex and surfaces every driver's completion rate mid-wave — not after Monday's scorecard. It is"," ",e.jsx("a",{"data-loc":"client/src/content/blog/amazon-cortex-dcr-score.tsx:231",href:"/amazon-dsp-management-software",children:"Amazon DSP management software"})," ","built specifically for UK operators, with a 14-day free trial and no credit card required."]})]})}function a(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:4",children:"Onboarding a new driver at an Amazon DSP is never just a paperwork exercise. You are bringing someone into a role where a single missed compliance check can cost you a corrective action, and where a poorly trained first week often turns into a problem driver for months. Most DSP owners get this right eventually — but by trial and error, not by design. This guide lays out a repeatable process so that every new hire arrives at their first wave ready to perform and fully compliant."}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:13",children:"Before the first shift: the compliance paperwork that cannot wait"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:14",children:"Amazon requires every DA to be cleared through its own background check process before they can deliver. That process takes time, and you cannot control the timeline — but you can make sure everything on your side is sorted before the check comes back, not after."}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:19",children:"The minimum you need in place before a new driver's first shift:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:22",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:23",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:24",children:"Right-to-work verification."})," You are legally required to check and retain a copy of the documents that prove your driver has the right to work in the UK. This is not optional and does not have a grace period. Do it before they start, not on their first day while they are standing in front of you."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:29",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:30",children:"Driving licence check."})," Check the DVLA record, not just the physical licence. You need to confirm the correct vehicle category (usually B for a standard van), verify there are no disqualifying endorsements, and note the expiry date so you can set a reminder to re-check. Photocopying a licence does not tell you its status."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:35",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:36",children:"Insurance notification."})," Add the new driver to your fleet insurance schedule. If a driver has an accident before they are added, your cover may not apply."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:39",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:40",children:"Emergency contact and employment contract."})," Basic, but often processed in the rush of a busy hiring period. Both need to be signed and filed before the first day."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:44",children:"Set up a standard checklist that your dispatcher or OSM works through for every hire, without exception. If even one item is skipped under pressure, you will eventually face the consequence."}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:50",children:"What Amazon checks at station — and what you should prepare for"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:51",children:"Your new DA will go through Amazon's own station induction. What that covers varies slightly by station, but you should assume it will include: the Rabbit device setup, the Mentor app, the delivery app walkthrough, and a van safety briefing. Your job is not to duplicate what Amazon covers — it is to brief your driver on everything Amazon does not cover about working for your DSP specifically."}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:58",children:"That briefing should cover your expectations on:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:61",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:62",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:63",children:"Photo on Delivery (POD) compliance."})," New drivers often understand they need to take photos but do not understand the consequence of missing them. Walk through the POD requirement explicitly and show them what a compliant photo looks like."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:67",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:68",children:"Van inspection before every shift."})," Explain that a daily check-sheet is not a formality — it is how you document pre-existing damage and keep your fleet insurance clean. Make clear that missed inspections have consequences."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:72",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:73",children:"What to do when a delivery cannot complete."})," Many DNR claims and Contact Compliance misses come from drivers who did not know the right procedure for an undeliverable stop. Cover Contact Compliance and how to log exceptions clearly."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:77",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:78",children:"Shift start time and what late arrival means for the wave."})," New drivers often do not realise that being 20 minutes late at the station ripples through to over-stopped routes and incomplete waves."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:84",children:"Setting new drivers up in your systems"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:85",children:"Before a new driver's first shift, they need to exist in every system your operation runs through — not just Amazon's. That means:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:89",children:[e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:90",children:"Adding them to your rota software so they can be scheduled and can see their shifts in advance."}),e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:94",children:"Creating their profile in your performance tracking tool so you can start monitoring their metrics from day one rather than scrambling for data after their first week."}),e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:98",children:"Storing their right-to-work documents, licence details, and licence expiry date in a searchable place — not a filing cabinet and not a folder on someone's laptop."}),e.jsx("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:102",children:"Setting up a licence re-check reminder. Licence expiry typically comes around 10 years after issue. That is far enough away to feel irrelevant at onboarding, which is exactly why it gets missed."})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:109",children:"The first two weeks: building the habits that stick"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:110",children:"The first two weeks are when a new driver's habits are formed. The drivers who become consistent performers are almost always the ones who received consistent feedback in their first fortnight — not a one-off induction and then silence until something went wrong."}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:115",children:"A simple structure that works:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:118",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:119",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:120",children:"End of day 1:"})," a brief check-in on how the wave went, any confusion about procedures, any equipment issues. Takes five minutes and catches the problems that will become habits if left unaddressed."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:124",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:125",children:"End of week 1:"})," share their actual scorecard metrics with them — POD rate, completion rate, any DNR flags. Make sure they know how to read the numbers and what they mean for their role. Drivers who see their own data early take ownership of it."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:129",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:130",children:"End of week 2:"})," a proper one-to-one. What is going well, what needs work, any route or scheduling adjustments needed. By this point you have two weeks of data to work from rather than an impression."]})]}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:135",children:"The DSPs with the lowest driver turnover are the ones where new starters feel visible and supported from the beginning. That is not about being soft on performance — it is about being clear about expectations and consistent about feedback."}),e.jsx("h2",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:141",children:"Where DSPOps fits in"}),e.jsx("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:142",children:"DSPOps centralises the compliance and performance side of driver onboarding. Right-to-work status, licence details, and expiry reminders are stored per driver and surfaced automatically when they are coming due — so nothing gets missed because someone forgot to check a spreadsheet. New drivers appear in the performance dashboard from their first shift, so your OSM can monitor their metrics and run the week-one review with actual numbers rather than impressions."}),e.jsxs("p",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:150",children:["If you want to see how the onboarding and compliance workflows work inside DSPOps, you can"," ",e.jsx("a",{"data-loc":"client/src/content/blog/how-to-onboard-new-drivers-amazon-dsp.tsx:152",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"book a 20-minute demo"})," ","— we will walk through your specific setup and show you what it looks like for your fleet."]})]})}function s(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:4",children:"Driver turnover is one of the most expensive problems a UK Amazon DSP can face. Every time a driver leaves you absorb the cost of recruiting, right-to-work checks, station induction, and a two-to-four week performance dip while the new hire finds their feet. Meanwhile your Cortex scorecard takes the hit. Yet most DSP owners treat turnover as an inevitable cost of the industry rather than something they can actively manage down. The operators with the lowest churn are usually doing a handful of concrete things differently — and none of them require a big HR budget."}),e.jsx("h2",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:13",children:"Understand why drivers actually leave"}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:14",children:`Exit interviews rarely tell the full story. Drivers leaving an Amazon DSP almost never say "I didn't like the job" — they give vague reasons because they don't expect management to care. What the data consistently shows is that most departures fall into three buckets:`}),e.jsxs("ul",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:19",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:20",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:21",children:"Unpredictable schedules."})," Drivers who can't plan their personal lives around their working week start looking elsewhere quickly. Last-minute rota changes, cancelled shifts, and inconsistent start times erode trust fast."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:25",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:26",children:"Feeling managed by metrics they don't understand."}),` A driver pulled into the office for a "low POD score" who doesn't know what POD means, doesn't see their own numbers day-to-day, and hears about problems only once a week will feel blindsided — not coached.`]}),e.jsxs("li",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:30",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:31",children:"No visible career path or recognition."})," Delivery driving is hard physical work. When drivers see no difference in how the top performers are treated versus the average, the motivation to stay disappears."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:37",children:"The first 90 days: where most churn is decided"}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:38",children:"New drivers form their opinion of your operation within the first three months. If onboarding is disorganised, if no one checks in after week two, and if the first feedback they receive is negative, you've already lost them — they're just working their notice period in their head."}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:43",children:"A structured 90-day touchpoint routine changes this. Week one: a buddy or lead driver alongside them for at least two shifts. Week two: a brief one-to-one to go through their metrics — show them their own numbers in a way that feels like coaching, not a warning. Week four: a formal check-in on how they're finding the role. Month three: a review conversation that makes clear what good progression looks like at your DSP. Drivers who receive this structure in the first 90 days are far more likely to still be with you at month twelve."}),e.jsx("h2",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:52",children:"Give drivers visibility of their own performance"}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:53",children:"One of the most effective retention tools costs nothing extra: show drivers their own Cortex metrics daily, not just when something goes wrong. When a driver can see their own DCR, POD compliance, and contact rate in real time, two things happen. First, the intrinsically motivated drivers self-correct without any management input — they don't want to be at the bottom of the leaderboard. Second, conversations about performance shift from confrontational to collaborative, because the driver isn't hearing bad news for the first time."}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:61",children:"Drivers who feel informed rather than surveilled are markedly more likely to stay."}),e.jsx("h2",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:65",children:"Run rotas with enough notice to matter"}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:66",children:"Publishing the rota with less than a week's notice is a churn accelerator. Drivers with families, second jobs, or caring responsibilities simply cannot plan around a rolling week. The industry standard that Amazon itself expects from its station partners is meaningful advance notice — yet many DSPs still finalise shifts two or three days out because the demand picture feels uncertain."}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:72",children:"The fix is to build the rota around your baseline contracted headcount and treat last-minute demand spikes as a flex layer — overtime volunteers, not schedule rewrites. This single change consistently reduces voluntary turnover because drivers stop feeling like they have no control over their time."}),e.jsx("h2",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:78",children:"Make recognition visible and regular"}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:79",children:"A brief shout-out in the morning huddle for the driver with the highest POD score that week costs nothing and signals to the whole team that performance is noticed. Leaderboards — visible at the station or sent directly to drivers — create a culture of friendly competition that keeps engaged drivers engaged. The drivers who care about being top of the board are usually your most reliable people; make them feel seen and they will stay."}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:86",children:"Recognition doesn't need to mean bonuses. Consistency matters more than size. A driver who hears positive feedback weekly internalises that this DSP is one worth staying at."}),e.jsx("h2",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:91",children:"Spot at-risk drivers before they hand in notice"}),e.jsx("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:92",children:"Churn usually shows up in the metrics before it shows up in a resignation. A driver whose performance has been declining for three weeks — more late returns, lower POD, skipped contacts — is disengaged. That's the intervention window. A ten-minute conversation, an offer to look at their route, or a schedule adjustment is often all it takes. By the time they've handed in notice, you've missed it."}),e.jsx("h2",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:99",children:"Where DSPOps fits in"}),e.jsxs("p",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:100",children:["DSPOps gives your operations manager the daily per-driver visibility that makes all of this practical. Rotas are built and communicated in advance through a single tool. Driver metrics surface automatically so your morning huddle runs in minutes rather than spreadsheet rebuilds. Drivers access their own numbers through the driver portal — which shifts the culture from top-down management to transparent coaching. If you want to see how it works for a DSP your size, you can"," ",e.jsx("a",{"data-loc":"client/src/content/blog/reduce-driver-turnover-amazon-dsp.tsx:106",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"book a 20-minute demo"})," ","and we'll walk through it with your actual setup."]})]})}function i(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:4",children:"Van inspections are one of those tasks that feel administrative until the day they aren't. A tyre blowout on the A-road, a brake fault flagged by Amazon's audit team, or a driver involved in a minor collision in a vehicle with a pre-existing dent that nobody documented — suddenly your compliance record becomes the most important thing in the building. For UK Amazon DSP owners, daily vehicle checks are not optional. They are a contractual obligation, a legal requirement under road traffic law, and one of the cleaner ways to protect both your drivers and your DA agreement."}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:12",children:"The problem is that most DSPs know this in principle but have gaps in practice. Paper logs get lost. Drivers tick boxes without looking. Faults get reported verbally and never actioned. By the time an Amazon ops audit lands or a vehicle goes off the road, the record is incomplete and the liability is yours. Here is what Amazon actually checks, where DSPs typically fall short, and how to build a process that holds up."}),e.jsx("h2",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:20",children:"What Amazon checks during a vehicle compliance audit"}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:21",children:"Amazon's operations team and Delivery Service Partner support managers periodically review vehicle compliance as part of broader DA performance checks. The specific items vary, but auditors consistently look at:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:26",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:27",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:28",children:"Daily walkaround inspection records"})," — evidence that a pre-departure check was completed by the driver for each vehicle, each day. Missing dates are an immediate flag."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:31",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:32",children:"Fault reporting and resolution logs"})," — if a driver reported a fault, what was done about it and when? Unresolved faults left on vehicles are serious."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:35",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:36",children:"Tyre condition and tread depth records"})," — both the inspection log and the physical tyres must match. Auditors will check the vehicle as well as the paperwork."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:39",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:40",children:"Brake and lighting checks"}),' — walkaround logs that consistently show lights and brakes as "pass" with no variation across months raise questions about whether checks are genuine.']}),e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:43",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:44",children:"Vehicle damage records"})," — pre-existing dents, scrapes, and mirror damage must be documented. If damage appears in a collision report that was never on the inspection record, it implies drivers were not conducting proper checks."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:50",children:"Where DSPs typically fall short"}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:51",children:"The most common gap is not that DSPs skip inspections entirely — it is that inspections happen without documentation, or documentation exists but is incomplete, inconsistent, or inaccessible."}),e.jsxs("ul",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:55",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:56",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:57",children:"Paper logs left in the van."})," A logbook that lives in the glovebox works fine until you need to pull a specific date's inspection to respond to an audit request. Finding a specific sheet from six weeks ago, across a fleet of twelve vans, takes time you don't have."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:61",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:62",children:"No photos."})," Written tick-box records alone do not prove condition. A photo taken at the start of each shift, time-stamped and linked to the driver and vehicle, is the closest thing to an audit-proof record."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:66",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:67",children:"Fault reporting that relies on memory."})," Drivers report faults at the end of a nine-hour shift, often verbally to an OSM who is handling five other things. By the next morning, the fault is forgotten or the wrong van gets flagged."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:71",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:72",children:"No clear pass/fail criteria."}),' "Checked tyres" means different things to different drivers. Without a defined checklist — minimum tread depth, what counts as reportable damage — results vary wildly across your fleet.']})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:78",children:"Building a daily pre-departure routine that actually sticks"}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:79",children:"The operational pattern that works is simple: make the walkaround a gate to dispatch, not an afterthought. A driver who cannot show a completed inspection does not leave the yard. When it is enforced consistently in the first week, drivers do not test it in week two."}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:84",children:"The checklist itself should take no more than three to four minutes and cover: tyres (condition and pressure), lights (all round), brakes (foot and handbrake), mirrors, wipers, bodywork damage, and cargo door operation. For electric vehicles, add charge level. The key is that the result is recorded digitally, with a photo, before the engine starts. Paper can be signed in ten seconds in the van at the end of the day; a timestamped mobile entry cannot."}),e.jsx("h2",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:92",children:"What to do when a driver reports a fault"}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:93",children:'Every fault report needs three things: an immediate decision (is the vehicle safe to dispatch?), a maintenance action with a named owner and a date, and a closed loop confirming the fault was resolved. If your process only has the first step, faults are reported but not fixed. If you have all three logged in one place, an auditor asking "what happened with the nearside mirror on van 7 on the 3rd?" gets an answer in thirty seconds.'}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:100",children:"Keep vehicles with outstanding safety-critical faults off the road. The pressure to put every van out during peak weeks is real, but dispatching a vehicle with a known braking issue is not a compliance risk — it is a criminal liability if something goes wrong."}),e.jsx("h2",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:106",children:"Keeping records that hold up under scrutiny"}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:107",children:"DVSA guidance and Amazon's own compliance expectations both point in the same direction: digital, timestamped, driver-linked records are far stronger than paper ones. At minimum you want:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:111",children:[e.jsx("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:112",children:"A record for every vehicle, every operational day"}),e.jsx("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:113",children:"Photographic evidence attached to the record"}),e.jsx("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:114",children:"Any reported faults linked through to resolution"}),e.jsx("li",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:115",children:"Records retained for at least twelve months"})]}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:117",children:"If you are using a shared spreadsheet or paper logbook today, the question is not whether it will fail an audit — it is when. Digital records are retrievable, searchable, and do not depend on a driver remembering to fill in the sheet before handing the keys back."}),e.jsx("h2",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:123",children:"How DSPOps can help"}),e.jsx("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:124",children:"DSPOps includes a built-in van inspection app that lets drivers complete daily walkaround checks on their phone, with photos, before each shift. Faults are flagged immediately to the OSM, tracked through to resolution, and stored in a searchable log against the vehicle and driver. When an audit request comes in, you pull the date range and export — no digging through glovebox folders."}),e.jsxs("p",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:131",children:["If your current inspection process relies on paper or verbal reporting, it's worth seeing what a digital record looks like for your fleet."," ",e.jsx("a",{"data-loc":"client/src/content/blog/van-inspection-compliance-amazon-dsp.tsx:134",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"Book a 20-minute demo"})," ","and we'll walk through the inspection workflow live."]})]})}function c(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:4",children:"Most DSP driver briefings are rushed — a few words before the van doors close, a reminder to take photos on every drop, then out the gate. By 9 AM the fleet is on the road and the OSM is already firefighting yesterday's problems instead of preventing today's."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:9",children:"The pre-wave briefing is the cheapest performance management tool a DSP owner has. Done consistently, with the right data, it moves Cortex metrics faster than any retraining programme or policy memo. Done badly — or skipped — and the same problems repeat week after week."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:16",children:"Why the briefing matters more than most owners realise"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:17",children:"Amazon's scorecard metrics — DCR, POD, CC, DNR — are measured daily, but they're shaped in the thirty minutes before drivers leave the station. A driver who understands exactly why their POD compliance matters, and who hears from their manager every morning that it's being tracked, makes different decisions on the road."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:23",children:"Feedback loops in Amazon's system are long. Drivers often don't see the consequence of a missed contact attempt or a skipped delivery photo until the scorecard drops the following Monday. The morning briefing closes that loop the same day — before a problem compounds across a full week of routes."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:30",children:"What to cover in ten minutes or less"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:31",children:"Effective briefings are short and specific. A ten-minute structure that works in practice:"}),e.jsxs("ul",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:34",children:[e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:35",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:36",children:"Safety update (1–2 minutes):"}),' one specific road condition, weather note, or incident from the previous day — not a generic "drive safely." Specific details are memorable; vague reminders are not.']}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:40",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:41",children:"Yesterday's metric call-outs (3–4 minutes):"})," name the two or three drivers whose POD, CC, or DCR numbers were below standard, and address it directly. Drivers who are never named take shortcuts; drivers who expect to be named don't."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:45",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:46",children:"Address flags (2–3 minutes):"})," any stops that generated DNR claims or customer complaints in the past week. Routes repeat — the same problematic addresses come up again. Flag them before drivers load, not after they've already attempted the drop."]}),e.jsxs("li",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:51",children:[e.jsx("strong",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:52",children:"Route or staffing changes (1–2 minutes):"})," cover-driver assignments, route swaps, any late changes to the wave. Unclear handovers are a common source of RTS events and missed stops."]})]}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:58",children:"The data you need before you can brief properly"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:59",children:"The briefing is only as useful as the information behind it. An OSM going into a morning huddle without per-driver metrics from the previous day is guessing — and drivers know it."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:63",children:"Before the briefing starts, you need to know: which drivers had POD compliance below threshold yesterday, which routes had CC misses, and whether any DNR flags landed overnight. If gathering that information takes thirty minutes of pulling Cortex exports and rebuilding spreadsheets, the briefing either gets skipped or happens without the numbers."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:70",children:"This is the operational case for live driver-level data your OSM can open in thirty seconds. The briefing should take ten minutes. Finding the data to run it shouldn't take longer than that."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:76",children:"How to brief drivers who aren't at the station"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:77",children:"Many DSPs run split shifts, use remote loading points, or have a portion of the fleet that doesn't come through the main station before dispatch. The briefing still matters — it just changes format."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:82",children:"A WhatsApp voice note sent before drivers leave home is a pragmatic substitute. Keep it under ninety seconds: one safety note, two metric call-outs from yesterday, and any address flags relevant to that driver's area. Written briefing notes work too, but they get skimmed — a voice message is harder to ignore."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:88",children:"For drivers you know won't engage on their own, a short video call just before dispatch achieves the same outcome and gives you the chance to confirm they understood. Fifteen minutes spent on this is worth more than thirty minutes managing a DNR claim in the afternoon."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:95",children:"Building the habit: the ten-week arc"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:96",children:"The first week of consistent briefings feels awkward. Drivers aren't used to being named in front of their colleagues, and managers feel uncomfortable delivering direct feedback to a group. Push through it — the discomfort is doing the work."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:101",children:"By week three, drivers start self-correcting before you call them out. By week six, the best performers are coming to the briefing early because they want to hear where they rank. By week ten, the briefing is part of the station's culture, and skipping it feels wrong to everyone — not just the manager."}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:107",children:"The one thing that kills the habit before it takes root: running a briefing without data. If the OSM has nothing specific to say — no driver names, no metric numbers — the session becomes a pep talk. Drivers tune it out within a week, and the habit never forms."}),e.jsx("h2",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:113",children:"Where DSPOps fits in"}),e.jsx("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:114",children:"DSPOps pulls the previous day's Cortex data — POD compliance, CC rates, DNR flags — into a single dashboard your OSM can open on a tablet while drivers are loading. Every metric is broken down by driver, so the names and numbers are in front of you before the briefing starts. No rebuilding spreadsheets, no waiting for a Cortex export to arrive."}),e.jsxs("p",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:120",children:["If you want to see how it looks in practice,"," ",e.jsx("a",{"data-loc":"client/src/content/blog/amazon-dsp-driver-briefings.tsx:122",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"book a 20-minute demo"})," ","— we'll walk through a live briefing flow using your own station's data."]})]})}const l=[{slug:"amazon-dsp-driver-briefings",title:"How to run effective driver briefings before a delivery wave",description:"How UK Amazon DSP owners can run a 10-minute pre-wave driver briefing that improves POD, CC, and DCR — without adding more meetings to the day.",excerpt:"Most DSP driver briefings are rushed and generic. A ten-minute structured briefing with yesterday's Cortex data does more for your scorecard than any retraining session.",date:"2026-06-22",readingMinutes:5,Body:c},{slug:"van-inspection-compliance-amazon-dsp",title:"Van inspection compliance: what Amazon audits and what DSPs miss",description:"What Amazon checks in a van inspection audit, where UK DSPs fall short on vehicle compliance, and how to build a daily walkaround routine that holds up under scrutiny.",excerpt:"Van inspections feel administrative until the day they aren't. Here is what Amazon audits, where most DSPs have gaps, and how to build a process that actually holds up.",date:"2026-06-15",readingMinutes:5,Body:i},{slug:"reduce-driver-turnover-amazon-dsp",title:"How to reduce driver turnover at an Amazon DSP",description:"Practical steps UK Amazon DSP owners can take to reduce driver churn — from structured 90-day onboarding to rota visibility and daily performance feedback.",excerpt:"Driver turnover is one of the most expensive problems a DSP can face. Here are the operational changes that keep drivers around long-term.",date:"2026-06-08",readingMinutes:5,Body:s},{slug:"how-to-onboard-new-drivers-amazon-dsp",title:"How to onboard new drivers at an Amazon DSP",description:"A step-by-step guide to onboarding new Amazon DSP drivers in the UK — right-to-work checks, licence verification, station induction, and the two-week follow-up routine.",excerpt:"Most DSP driver problems start in week one. Here is the compliance checklist and two-week routine that turns new starters into consistent performers.",date:"2026-06-01",readingMinutes:5,Body:a},{slug:"amazon-cortex-dcr-score",title:"What is a good Amazon Cortex DCR score, and how do you improve it?",metaTitle:"Amazon Cortex DCR Score: What's Good and How to Improve It",description:"What DCR means on your Amazon Cortex scorecard, what counts as a good score, and the exact steps UK DSPs use to push it higher.",excerpt:"Your Amazon Cortex DCR score defines your week. Here's what counts as a good score, why it drops, and the per-driver playbook to fix it fast.",date:"2026-05-29",readingMinutes:7,Body:r},{slug:"improve-amazon-cortex-scorecard",title:"How to improve your Amazon Cortex scorecard",description:"A practical guide for DSP owners on lifting DCR, DPMO, DNRs, POD, CC, and CDF — week by week.",excerpt:"Every Amazon DSP owner stares at the Cortex scorecard on Monday. Here's the per-metric playbook to actually move the numbers.",date:"2026-05-18",readingMinutes:7,Body:n}];function h(t){return l.find(o=>o.slug===t)}export{l as b,h as g};
